## Application Workaround
For those reaching this issue that need functionality after 1.0.3 the following code works with 1.0.10
```
def get_issues(authed_jira, jql, startAt=0, maxResults=False,
               fields="description,summary,resolution,labels"):
    query = None
    issues = []
    increment = 50
    if maxResults != False and isinstance(maxResults, int):
        if maxResults < 1:
            raise TypeError("maxResults - must be a positive integer.")
        else:
            increment = 50 if maxResults > 50 else maxResults
    else:
        increment = 50

    if isinstance(jql, dict):
        query = issue_to_jql(jql)
    elif isinstance(jql, str):
        query = jql
    else:
        raise ValueError ("Expected type 'str' or 'dict'.")
    
    results = authed_jira.search_issues(query, maxResults=maxResults, fields=fields)
    for issue in results:
        issues.append(issue)
    startAt += increment
    
    total_issues = results.total
    if not maxResults:
        while len(issues) < total_issues:
            for issue in results:
                issues.append(issue)
            startAt += increment
            results = authed_jira.search_issues(query, startAt=startAt,
                maxResults=increment, fields=fields)
            total_issues = results.total

    else:
        while len(issues) < maxResults:
            for issue in results:
                issues.append(issue)
            startAt += increment
            if (startAt + increment) > maxResults:
                increment = maxResults - startAt
            results = authed_jira.search_issues(query, startAt=startAt,
                maxResults=increment, fields=fields)
    if len(issues) != total_issues:
        print ("Expected: {}, Found: {}".format(total_issues, len(issues)))
    return issues
```

## Helper Function
```
def issue_to_jql(issue, **kwargs):
    search = []
    for key in kwargs:
        search.append("{field} {op} {value}".format(field=key,
            op=kwargs[key][0], value=kwargs[key][1]))
    for lhs, rhs in issue.items():
        if isinstance(rhs, dict):
            for k, v in rhs.items():
                search.append("{field} {op} '{value}'".format(field=lhs,
                    op="=", value=v))
        else:
            if lhs == "labels":
                search.append("labels in ('{}')".format("','".join(rhs)))
            else:
                search.append("{field} {op} '{value}'".format(field=lhs,
                    op="=", value=rhs))
    return " AND ".join(search)
```

