Okay so now I think i do not need scripting but it is really nice. So I think I can handle everything inside each command also the time triggered behavior. And there is also some CmdResult I do not know before I have looked into the examples.

 ```python

import threading
import time
from random import randint

from cmd2 import Cmd, CmdResult

TIMEOUT_CMD2 = 5


class Job(Cmd):
    def __init__(self, name=''):
        self.name = name
        self.state = 'not started'
        self._connected = False
        Cmd.__init__(self, use_ipython=False)

    def _try_to_connect(self):
        sleep_time = randint(0, 5)
        print("wait for {} seconds".format(sleep_time))
        time.sleep(sleep_time)

        if 2 <= sleep_time <= 3:
            self._connected = True
            print("connected...")
        else:
            self._connected = False
            print("could not connect...")

        # save connected state in CmdResult
        self._last_result = CmdResult(self._connected)

    def do_connect(self, *args):
        self.state = 'try to connect to something ...' + str(args)
        t = threading.Thread(target=self._try_to_connect)
        t.start()
        t.join()
        if self._last_result:
            print("also do_connect says connected")
        else:
            print("also do_connect says could not connect")

    def do_disconnect(self, *args):
        if self._connected:
            self._connected = False
            self._last_result = None

    def do_cmd1(self, *args):
        if self._last_result is not None:
            print("last result was {}".format(self._last_result))
            self._last_result = None
        else:
            print("last result was None {}".format(self._last_result))

        if not self._connected:
            print("return because not connected")
            return

        self.state = 'command 1' + str(args)
        print(self)

    def do_cmd2(self, *args):

        if not self._connected:
            print("return because not connected")
            return

        self.state = 'command 2' + str(args)
        print(self)

    def do_cmd3(self, *args):

        if not self._connected:
            print("return because not connected")
            return

        print("... start ...")
        start_time = cur_time = time.time()
        self.state = 'command 3' + str(args)
        print(self)
        while cur_time <= start_time + TIMEOUT_CMD2:
            time.sleep(1)
            cur_time = time.time()
        print("... ende ...")

    def __str__(self):
        return 'job %(name)s %(state)s' % vars(self)


if __name__ == '__main__':
    job = Job()
    job.cmdloop()
```

So I think i can handle the timing in each command by using some class variables. So in the cmd3 command I measure the start and wait for some time. And i also can skip commands if I am not connect and so on. Do you think it is a bad style if I manage this in that way?

Take a look at the example in the documentation for `OtherException`; it shows what you want (if you drop the `MyCustomException` part of the code):

```C++
py::register_exception_translator([](std::exception_ptr p) {
    try {
        if (p) std::rethrow_exception(p);
    } catch (const OtherException &e) {
        PyErr_SetString(PyExc_RuntimeError, e.what());
    }
});
```
in your case, you'll want one catch for the C++ type that becomes `AssertionError` (using `PyExc_AssertionError`) and another to catch and set `PyExc_NotImplementedError`.  (The full list of built-in exceptions is at https://docs.python.org/3/c-api/exceptions.html#standard-exceptions).

